import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import ShareGShop from './ShareGShop';
import { TrustStars } from './TrustCenter';
import {
  Briefcase, Megaphone, MapPin, UserCircle
} from './Icons';

const API_URL = process.env.REACT_APP_API_URL || '';

function Dashboard({ user }) {
  const navigate = useNavigate();
  const [trust, setTrust] = useState(null);
  const [openJobs, setOpenJobs] = useState(null);

  useEffect(() => {
    const token = localStorage.getItem('token');
    axios.get(`${API_URL}/api/users/me/trust`, { headers: { Authorization: `Bearer ${token}` } })
      .then(res => setTrust(res.data))
      .catch(() => {});
    axios.get(`${API_URL}/api/jobs?status=open&limit=50`, { headers: { Authorization: `Bearer ${token}` } })
      .then(res => setOpenJobs(Array.isArray(res.data) ? res.data.length : null))
      .catch(() => {});
  }, []);

  const quickActions = [
    { icon: Briefcase, label: 'Help Needed', sub: 'Ask your neighbours', color: 'bg-blue-600', hover: 'hover:bg-blue-700', onClick: () => navigate('/jobs') },
    { icon: Megaphone, label: 'Lend a Hand', sub: 'Offer your help', color: 'bg-indigo-600', hover: 'hover:bg-indigo-700', onClick: () => navigate('/create-service') },
    { icon: MapPin, label: 'Neighbours Nearby', sub: 'Meet people close by', color: 'bg-green-600', hover: 'hover:bg-green-700', onClick: () => navigate('/map') },
    { icon: UserCircle, label: 'My Profile', sub: 'Your story & skills', color: 'bg-purple-600', hover: 'hover:bg-purple-700', onClick: () => navigate('/profile') },
  ];

  return (
    <div className="max-w-4xl mx-auto p-4">
      {/* Welcome Banner */}
      <div className="bg-gradient-to-r from-blue-600 to-purple-600 rounded-2xl p-5 sm:p-6 mb-4 text-white">
        <div className="flex items-center justify-between flex-wrap gap-4">
          <div>
            <h2 className="text-xl sm:text-2xl font-bold">Hey {user?.name?.split(' ')[0]} 👋</h2>
            <p className="text-blue-100 mt-1 text-sm">
              {openJobs > 0
                ? `${openJobs} open job${openJobs === 1 ? '' : 's'} near you right now`
                : 'What can you share with your community today?'}
            </p>
          </div>
          <div className="text-right">
            <div className="text-2xl sm:text-3xl font-bold">R{user?.randBalance ?? 0}</div>
            <div className="text-blue-200 text-xs sm:text-sm">Rands available</div>
          </div>
        </div>
      </div>

      {/* Trust nudge — only when there are stars to earn */}
      {trust && trust.score < 100 && (
        <button onClick={() => navigate('/verification')}
          className="w-full flex items-center gap-3 bg-amber-50 border border-amber-200 rounded-2xl p-4 mb-4 text-left hover:bg-amber-100 transition-all">
          <span className="text-2xl flex-shrink-0">🛡️</span>
          <span className="flex-1 min-w-0">
            <span className="flex items-center gap-2 flex-wrap">
              <TrustStars stars={trust.stars} size={14} />
              <span className="text-xs font-bold text-amber-700">{trust.level}</span>
            </span>
            <span className="block text-xs text-amber-800 mt-1 font-medium">
              Earn more trust stars — verify your phone or ID to win more jobs
            </span>
          </span>
          <span className="text-amber-500 font-bold text-lg flex-shrink-0">›</span>
        </button>
      )}

      {/* Quick Actions — 2x2 grid, larger touch targets */}
      <div className="grid grid-cols-2 gap-3 mb-4">
        {quickActions.map(btn => (
          <button key={btn.label} onClick={btn.onClick}
            className={`flex flex-col items-center justify-center gap-2 ${btn.color} text-white p-5 sm:p-6 rounded-2xl ${btn.hover} transition-all shadow-md text-center min-h-[120px]`}>
            <btn.icon size={32} strokeWidth={2} className="text-white shrink-0" />
            <div>
              <div className="font-bold text-sm sm:text-base">{btn.label}</div>
              <div className="text-[11px] opacity-80">{btn.sub}</div>
            </div>
          </button>
        ))}
      </div>

      {/* Share Sebenza */}
      <ShareGShop user={user} />
    </div>
  );
}

export default Dashboard;
